// Global Memory: in[N], out[N]
// Local Buffer:  buf[TILE_SIZE]
for (int i = 0; i < N; i += TILE_SIZE) {
    // 1. Load Tile
    for (int j = 0; j < TILE_SIZE; j++) buf[j] = in[i+j];

    // 2. Compute on Tile (High Reuse)
    process_tile(buf);

    // 3. Store Tile
    for (int j = 0; j < TILE_SIZE; j++) out[i+j] = buf[j];
}

