for (int sum = 0; sum < N + M; sum++) { // Wavefront index
    for (int i = 0; i < N; i++) {
        #pragma HLS PIPELINE II=1
        int j = sum - i; // Derive j
        if (j >= 0 && j < M) {
            // Now [i, j] and [i+1, j-1] are parallel safe
            update(buffer[i], buffer[i-1]);
        }
    }
}

